import{_ as a,o as t,c as d,a2 as o}from"./chunks/framework.Crpw6aS5.js";const b=JSON.parse('{"title":"DDS/CMake 多仓构建与互操作踩坑","description":"","frontmatter":{},"headers":[],"relativePath":"3 问题记录/DDS与CMake多仓构建及互操作踩坑.md","filePath":"3 问题记录/DDS与CMake多仓构建及互操作踩坑.md","lastUpdated":1781599722000}'),s={name:"3 问题记录/DDS与CMake多仓构建及互操作踩坑.md"};function r(i,e,n,l,c,p){return t(),d("div",null,[...e[0]||(e[0]=[o(`<h1 id="dds-cmake-多仓构建与互操作踩坑" tabindex="-1">DDS/CMake 多仓构建与互操作踩坑 <a class="header-anchor" href="#dds-cmake-多仓构建与互操作踩坑" aria-label="Permalink to &quot;DDS/CMake 多仓构建与互操作踩坑&quot;">​</a></h1> <h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h2> <p>DDS Wrapper 开发过程中四类高价值踩坑的复盘：DDS 跨厂商互操作崩溃、QoS 静默失配、monorepo 多仓构建顺序、idlcxx 输出冲突。每条都记录现象、根因链、修复方案和可复用经验。背景知识见 [[ROS2与DDS互操作深度解析]] 和 [[DDS Wrapper 架构设计与核心决策]]。</p> <h2 id="踩坑一-与-rmw-fastrtps-cpp-互通时-std-bad-alloc" tabindex="-1">踩坑一：与 rmw_fastrtps_cpp 互通时 std::bad_alloc <a class="header-anchor" href="#踩坑一-与-rmw-fastrtps-cpp-互通时-std-bad-alloc" aria-label="Permalink to &quot;踩坑一：与 rmw_fastrtps_cpp 互通时 std::bad_alloc&quot;">​</a></h2> <h3 id="现象" tabindex="-1">现象 <a class="header-anchor" href="#现象" aria-label="Permalink to &quot;现象&quot;">​</a></h3> <p>dds-wrapper（CycloneDDS 原生 API）发布 Topic，<code>rmw_fastrtps_cpp</code> 的 <code>ros2 topic echo</code> 订阅端崩溃 <code>std::bad_alloc</code>；<code>rmw_cyclonedds_cpp</code> 订阅端正常。</p> <h3 id="根因链" tabindex="-1">根因链 <a class="header-anchor" href="#根因链" aria-label="Permalink to &quot;根因链&quot;">​</a></h3> <p>通过三组控制变量实验 + Wireshark 抓包 + gdb 栈定位。崩溃发生在 <strong>discovery 阶段</strong>（不是数据传输阶段），栈顶是 <code>TypeInformation::deserialize</code>：</p> <div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>EDPBasePUBListener::add_writer_from_change</span></span>
<span class="line"><span>  → WriterProxyData::readFromCDRMessage    ← 解析 SEDP 参数列表</span></span>
<span class="line"><span>    → TypeInformation::deserialize          ← 反序列化 PID_TYPE_INFORMATION</span></span>
<span class="line"><span>      → vector::_M_default_append           ← 按错误数量分配</span></span>
<span class="line"><span>        → std::bad_alloc</span></span></code></pre> <div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><ol><li>dds-wrapper 用 CycloneDDS-CXX 原生路径，idlcxx 生成的代码<strong>自动注册 TypeObject</strong></li> <li>CycloneDDS 在 SEDP 宣告里自动附带 <code>PID_TYPE_INFORMATION</code>（0x75，100 字节）</li> <li>FastDDS <strong>无条件解析</strong>所有 PID，按自己的格式约定去读 <code>TypeInformation</code></li> <li>CycloneDDS 用 XCDR2 编码（符合 DDS-XTypes 1.3 §7.3.4.5），FastDDS 用 CDR1，解析依赖列表时读出错误数量 → 分配爆炸</li></ol> <h3 id="定性" tabindex="-1">定性 <a class="header-anchor" href="#定性" aria-label="Permalink to &quot;定性&quot;">​</a></h3> <p><strong>这是 FastDDS 的 bug（eProsira/Fast-DDS#1762），不是 dds-wrapper 或 CycloneDDS 的问题</strong>。CycloneDDS 能和 OpenDDS、RTI Connext 正常互通，唯独老版 FastDDS 不兼容。Foxy 捆绑的 FastDDS 版本较老，XTypes 实现不完整。<code>rmw_cyclonedds_cpp</code> 不触发此 bug，是因为它用自定义 sertype 注册，不附带 TypeObject。</p> <h3 id="修复方向" tabindex="-1">修复方向 <a class="header-anchor" href="#修复方向" aria-label="Permalink to &quot;修复方向&quot;">​</a></h3> <table tabindex="0"><thead><tr><th>方式</th> <th>结果</th></tr></thead> <tbody><tr><td>CycloneDDS XML 配置 <code>ProtocolVersion=2.1</code></td> <td>无效，PID_TYPE_INFORMATION 仍在</td></tr> <tr><td>CycloneDDS 配置 <code>IgnoreTypeInformation</code></td> <td>仅收端忽略，不影响发送</td></tr> <tr><td>CycloneDDS 编译关 type discovery</td> <td>仍在</td></tr></tbody></table> <p>可行方向：升级 ROS2 到较新版本（FastDDS #1762 修复已合入 2.0.x）/ 创建 topic/Writer 时不注册 TypeObject（搬 rmw_cyclonedds 的 sertype 方式）/ 单独升级 FastDDS。</p> <blockquote><p>经验：跨 DDS 互通要在 SEDP 层做 Wireshark 对比，关注 <code>PID_TYPE_INFORMATION</code> 这类 XTypes 相关 PID 的有无与编码格式，崩溃栈顶是定位关键。</p></blockquote> <h2 id="踩坑二-v4-action-与-ros2-互通超时-qos-静默失配" tabindex="-1">踩坑二：V4 Action 与 ROS2 互通超时（QoS 静默失配） <a class="header-anchor" href="#踩坑二-v4-action-与-ros2-互通超时-qos-静默失配" aria-label="Permalink to &quot;踩坑二：V4 Action 与 ROS2 互通超时（QoS 静默失配）&quot;">​</a></h2> <h3 id="现象-1" tabindex="-1">现象 <a class="header-anchor" href="#现象-1" aria-label="Permalink to &quot;现象&quot;">​</a></h3> <p>V3 Action 能与 <code>ros2 action send_goal</code> 互通，V4 不能，<code>wait_for_action_server()</code> 超时报 <code>Action server not available after 5s</code>。<strong>经历 8 轮排查才定位真因</strong>。</p> <h3 id="八轮排查的弯路" tabindex="-1">八轮排查的弯路 <a class="header-anchor" href="#八轮排查的弯路" aria-label="Permalink to &quot;八轮排查的弯路&quot;">​</a></h3> <table tabindex="0"><thead><tr><th>轮次</th> <th>假设根因</th> <th>结论</th></tr></thead> <tbody><tr><td>#1</td> <td>header 的 <code>uint64</code> 对齐 padding 与 wire 错位，改 <code>octet[8]</code></td> <td><strong>错误方向</strong></td></tr> <tr><td>#2</td> <td>CycloneDDS 版本不兼容 / 不发布初始 GoalStatusArray</td> <td>排除</td></tr> <tr><td>#3</td> <td><code>type_information</code> QoS 导致 graph_cache 不更新</td> <td>排除</td></tr> <tr><td>#4</td> <td>V3/V4 端点创建路径差异</td> <td>排除</td></tr> <tr><td>#5</td> <td>graph_cache / type_information / 创建路径假说</td> <td>排除</td></tr> <tr><td>#6</td> <td>缺 <code>ros_discovery_info</code> / enclave</td> <td><strong>被测试污染误导</strong>（隔离测试后推翻）</td></tr> <tr><td>#7</td> <td>feedback topic reliability QoS</td> <td><strong>真因</strong></td></tr> <tr><td>#8</td> <td>octet[8] 必要性对照实验</td> <td>证明 octet[8] 非必需，回退</td></tr></tbody></table> <h3 id="真正根因" tabindex="-1">真正根因 <a class="header-anchor" href="#真正根因" aria-label="Permalink to &quot;真正根因&quot;">​</a></h3> <p>V4 的 <strong>feedback topic reliability = BEST_EFFORT</strong>，应为 RELIABLE。ROS2 <code>rclcpp_action</code> client 用 RELIABLE 订阅 feedback。<strong>RELIABLE reader 与 BEST_EFFORT writer 的 QoS 不兼容</strong>，DDS 静默拒绝匹配 → client 的 feedback 订阅 matched-publisher 计数 = 0 → <code>rcl_action_server_is_available()</code> 的 5 项检查之一失败 → 判定 server 不可用 → 超时。</p> <p>修复仅 <code>node.hpp</code> 两行：</p> <div class="language-cpp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 修复前</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fbQos.reliability </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> DdsQoS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ReliabilityKind</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::BEST_EFFORT;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 修复后</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fbQos.reliability </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> DdsQoS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ReliabilityKind</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::RELIABLE;</span></span></code></pre> <div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="为什么查了-8-轮" tabindex="-1">为什么查了 8 轮 <a class="header-anchor" href="#为什么查了-8-轮" aria-label="Permalink to &quot;为什么查了 8 轮&quot;">​</a></h3> <ul><li>前面几轮对比的是 <code>send_goalRequest</code> reader 的 QoS 和 8 个 endpoint 的 type_information hash（都相同），<strong>唯独没逐项对比 feedback writer 的 reliability</strong></li> <li>standalone server trace 看起来&quot;SEDP 相同&quot;，是因为只比了类型相关字段，没比每个 endpoint 的 QoS</li> <li><strong>测试污染</strong>：V4 测试紧跟 V3 测试跑，ROS2 daemon/discovery 缓存残留 V3 的 graph 状态，让 V4 假阳性通过。隔离环境（每次 <code>killall</code> + sleep）重测才可信</li></ul> <h3 id="可复用经验" tabindex="-1">可复用经验 <a class="header-anchor" href="#可复用经验" aria-label="Permalink to &quot;可复用经验&quot;">​</a></h3> <ul><li><strong>QoS 不兼容是 DDS 的静默失败</strong>：DDS 不会报错，只是 matched 计数为 0，端点都在但收不到数据。调试互操作超时，<strong>第一件事是逐项对比每个 endpoint 的 QoS（尤其 reliability/durability）</strong>，不是看 type name</li> <li><strong>隔离测试是红线</strong>：连续测试不同实现会被 discovery 缓存污染，必须每次清环境</li> <li><strong>抓 client 侧 discovery trace</strong>，逐项比 server 各 endpoint 的 QoS，别只比类型字段</li> <li><strong>之前修过的 bug 迁移到新版本时要同步</strong>：这是 V3 历史 bug，V4 迁移时漏了</li></ul> <blockquote><p>附：<code>ros2 action send_goal</code> CLI 的超时是另一个独立限制——它需要节点在 <code>rt/ros_discovery_info</code> 上公告自己（成为 ROS2 node）。用 rclcpp_action 写的 client（如 <code>interop_action_client</code>）不受此限制，修好 feedback QoS 后完全正常。</p></blockquote> <h2 id="踩坑三-monorepo-多仓-clean-build-连环失败" tabindex="-1">踩坑三：monorepo 多仓 clean build 连环失败 <a class="header-anchor" href="#踩坑三-monorepo-多仓-clean-build-连环失败" aria-label="Permalink to &quot;踩坑三：monorepo 多仓 clean build 连环失败&quot;">​</a></h2> <h3 id="现象-2" tabindex="-1">现象 <a class="header-anchor" href="#现象-2" aria-label="Permalink to &quot;现象&quot;">​</a></h3> <p>dds-wrapper 与 proto-msg 同时在源码树时，<code>rm -rf build/*</code> 后 clean build 依次暴露三个错误（修一个冒一个）：configure 期跳过 DDS 段、build 期错误 127（command not found）、<code>fatal error: ...Time.hpp: 没有那个文件</code>。<strong>增量构建因产物已存在而掩盖全部问题。</strong></p> <h3 id="根因" tabindex="-1">根因 <a class="header-anchor" href="#根因" aria-label="Permalink to &quot;根因&quot;">​</a></h3> <p><strong>主因：配置顺序 proto-msg 先于 dds-wrapper。</strong> proto-msg 的 DDS 段在配置期需要 dds-wrapper 提供的三样东西（<code>dds_generate_messages</code> 宏、<code>dds_std_msgs</code> 目标、<code>DDS_STD_MSGS_WIRE_DIR</code> CACHE 变量），全部要等 dds-wrapper 的 <code>add_subdirectory</code> 跑完才存在。<code>find_omos_package</code> 兜不住——它只对不在树的仓库下载安装包，在树仓库只能靠 <code>add_subdirectory</code> 顺序提供。</p> <p>两个连带问题：</p> <ol><li><strong>IMPORTED 目标不跨子目录作用域</strong>：宏在 dds-wrapper 作用域 include <code>Python3::Interpreter</code>（<code>find_package</code> 创建的 IMPORTED 目标），却在 proto-msg 作用域调用 → 无法解析 → 字面量原样进 Makefile → 运行时报 <code>127 command not found</code></li> <li><strong>生成期 INCLUDES ≠ 编译期 -I</strong>：IDL 的 <code>#include</code> 靠 idlc <code>-I</code> 解析，但生成的 <code>.hpp</code> 在 C++ 编译期需要的 <code>-I</code> 是另一回事，须靠 <code>target_link_libraries(... PUBLIC ...)</code> 传播</li></ol> <h3 id="修复" tabindex="-1">修复 <a class="header-anchor" href="#修复" aria-label="Permalink to &quot;修复&quot;">​</a></h3> <table tabindex="0"><thead><tr><th>修复点</th> <th>方案</th></tr></thead> <tbody><tr><td>配置顺序</td> <td>manifest 中 dds-wrapper 移到 proto-msg 前</td></tr> <tr><td>IMPORTED 目标</td> <td>include 时缓存 <code>_DDS_PYTHON=\${Python3_EXECUTABLE}</code> 到全局 CACHE，COMMAND 改用普通路径变量</td></tr> <tr><td>C++ include 路径</td> <td><code>target_link_libraries(dds_demo_wire_lib PUBLIC dds_std_msgs_wire_lib)</code></td></tr> <tr><td>idlcxx 跨文件 include</td> <td><code>_generate</code> 屏障加入所有 wire IDL 文件；<code>-I</code> 只放 wire 树不放逻辑源码根（避免缺失时静默回退到错误版本）</td></tr></tbody></table> <h3 id="可复用经验-1" tabindex="-1">可复用经验 <a class="header-anchor" href="#可复用经验-1" aria-label="Permalink to &quot;可复用经验&quot;">​</a></h3> <ul><li><strong>clean build 是验收红线</strong>：增量构建会用上次产物，掩盖配置顺序 / 跨文件 include 顺序 / 跨作用域目标可见性问题。每次 CMake 改动后须 <code>rm -rf build/*</code> 重验</li> <li><strong>IMPORTED 目标不跨同级子目录作用域</strong>：宏里用 <code>find_package</code> 的 IMPORTED 目标做 <code>add_custom_command COMMAND</code>，跨子目录复用会失效。改用 include 时缓存的普通路径变量 + CACHE</li> <li><strong>生成期 INCLUDES ≠ 编译期 -I</strong>：跨仓库嵌套要两边都满足，后者靠链接传播</li> <li><strong>idlcxx 跨文件 include 须全量屏障</strong>：所有 wire IDL 必须在任何 idlcxx 编译前全部生成；<code>-I</code> 只放 wire 树，不放逻辑源码根，避免静默回退</li></ul> <h2 id="踩坑四-idlcxx-不同包同名消息输出冲突" tabindex="-1">踩坑四：idlcxx 不同包同名消息输出冲突 <a class="header-anchor" href="#踩坑四-idlcxx-不同包同名消息输出冲突" aria-label="Permalink to &quot;踩坑四：idlcxx 不同包同名消息输出冲突&quot;">​</a></h2> <h3 id="现象-3" tabindex="-1">现象 <a class="header-anchor" href="#现象-3" aria-label="Permalink to &quot;现象&quot;">​</a></h3> <p>不同包的同名消息（<code>pkg_a/msg/TestMsg</code> vs <code>pkg_b/msg/TestMsg</code>）在 idlcxx 生成时平铺到同一 OUTPUT_DIR 互相覆盖。</p> <h3 id="根因-1" tabindex="-1">根因 <a class="header-anchor" href="#根因-1" aria-label="Permalink to &quot;根因&quot;">​</a></h3> <p>直观解法是给 <code>idlcxx_generate</code> 传 <code>BASE_DIR</code> 让产物保留层级，但在本机不可行：</p> <table tabindex="0"><thead><tr><th>参数</th> <th>路径解析方式</th> <th>结果</th></tr></thead> <tbody><tr><td><code>BASE_DIR</code></td> <td><code>file(REAL_PATH)</code></td> <td><code>/mnt/vdb/...</code></td></tr> <tr><td><code>FILES</code></td> <td><code>get_filename_component(ABSOLUTE)</code></td> <td><code>/home/...</code></td></tr></tbody></table> <p>两者前缀不同，内部 <code>file(RELATIVE_PATH)</code> 产生 <code>../..</code> 相对路径触发 FATAL_ERROR。根子在于本机 <code>/home/user/project_ebox</code> 是符号链接 → <code>/mnt/vdb/home/user/project_ebox</code>，CMake 3.16 中两种路径规范化方向相反（ABSOLUTE 把 <code>/mnt/vdb</code> 还原回 <code>/home</code>，REAL_PATH 把 <code>/home</code> 解析为 <code>/mnt/vdb</code>），始终不一致。</p> <h3 id="修复-1" tabindex="-1">修复 <a class="header-anchor" href="#修复-1" aria-label="Permalink to &quot;修复&quot;">​</a></h3> <p><strong>按 sub_dir 分组，每组独立调用 <code>idlcxx_generate</code>，OUTPUT_DIR 包含 sub_dir 路径</strong>：</p> <div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pkg_a/msg/TestMsg.idl → OUTPUT_DIR dds_generated/pkg_a/msg/</span></span>
<span class="line"><span>pkg_b/msg/TestMsg.idl → OUTPUT_DIR dds_generated/pkg_b/msg/</span></span></code></pre> <div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>不依赖 BASE_DIR，完全规避符号链接问题。</p> <blockquote><p>经验：CMake 的 <code>REAL_PATH</code> 与 <code>ABSOLUTE</code> 对符号链接处理方向相反，混用会埋雷。涉及符号链接环境时，优先用显式分组 OUTPUT_DIR，避开 BASE_DIR 的相对路径计算。</p></blockquote> <h2 id="要点" tabindex="-1">要点 <a class="header-anchor" href="#要点" aria-label="Permalink to &quot;要点&quot;">​</a></h2> <ul><li><strong>DDS 互操作崩溃先看 SEDP discovery</strong>：抓包对比 <code>PID_TYPE_INFORMATION</code> 等 XTypes PID，崩溃栈顶（如 <code>TypeInformation::deserialize</code>）是定位关键。XCDR2 vs CDR1 是 CycloneDDS 与老版 FastDDS 的死结。</li> <li><strong>互操作超时先逐项比 QoS</strong>：QoS 不兼容是静默失败，别只盯 type name。RELIABLE reader + BEST_EFFORT writer 会被 DDS 静默拒绝。</li> <li><strong>互操作测试必须隔离环境</strong>：连续测试会被 ROS2 discovery 缓存污染，导致假阳性。每次 <code>killall</code> + sleep。</li> <li><strong>CMake 多仓改动必须 clean build 验收</strong>：增量构建掩盖配置顺序、跨作用域、跨文件 include 问题。</li> <li><strong>IMPORTED 目标不跨子目录作用域</strong>：跨子目录复用宏时，用 CACHE 路径变量替代 IMPORTED 目标。</li> <li><strong>符号链接环境下避开 <code>BASE_DIR</code></strong>：CMake <code>REAL_PATH</code> 与 <code>ABSOLUTE</code> 对符号链接处理相反，用显式分组 OUTPUT_DIR。</li></ul>`,106)])])}const _=a(s,[["render",r]]);export{b as __pageData,_ as default};
